class Persona {
    private String nombre;
    private int edad;

    public Persona(String nombre, int edad) {
        this.nombre = nombre;
        this.edad = edad;
    }
    public String getNombre() { return nombre; }
    public int getEdad() { return edad; }
}

class Empleado extends Persona {
    private String empresa;
    private double salario;

    public Empleado(String nombre, int edad, String empresa, double salario) {
        super(nombre, edad); // llama al constructor del padre
        this.empresa = empresa;
        this.salario = salario;
    }
    public String getEmpresa() { return empresa; }
}

q14.modelAnswer:
Agregación: la clase contenedora RECIBE el objeto ya creado (no lo crea ella). Los objetos contenidos pueden existir sin el contenedor.

class Jugador {
    private String nombre;
    public Jugador(String nombre) { this.nombre = nombre; }
    public String getNombre() { return nombre; }
}

class Equipo {
    private List<Jugador> jugadores;

    public Equipo(List<Jugador> jugadores) {
        this.jugadores = jugadores; // recibe objetos ya creados
    }
}

// Uso:
List<Jugador> lista = new ArrayList<>();
lista.add(new Jugador("Ana"));
Equipo equipo = new Equipo(lista); // los Jugadores existen antes del Equipo

