import java.util.ArrayList;

class Jugador {
    private String nombre;
    public Jugador(String nombre) { this.nombre = nombre; }
    public String getNombre() { return nombre; }
}

class Equipo {
    private ArrayList<Jugador> jugadores = new ArrayList<>();

    public void añadir(Jugador j) {
        jugadores.add(j);        // añadir
    }
    public void eliminar(Jugador j) {
        jugadores.remove(j);     // eliminar
    }
    public void listar() {
        for (Jugador j : jugadores) {  // recorrer
            System.out.println(j.getNombre());
        }
    }
}

q17.modelAnswer:
El constructor es un método especial que se ejecuta automáticamente al crear un objeto con new. Tiene el mismo nombre que la clase y no declara tipo de retorno.

class Persona {
    private String nombre;
    private int edad;

    // Constructor
    public Persona(String nombre, int edad) {
        this.nombre = nombre; // 'this.' distingue atributo del parámetro
        this.edad = edad;
    }
}

// Uso:
Persona p = new Persona("Carlos", 25); // llama al constructor

Si no defines constructor, Java crea uno vacío por defecto.
